    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css">
    <script>
        tailwind.config = {
            darkMode:"class",
            theme:{extend:{colors:{primary:"#8b5cf6",primaryGlow:"#a855f7",darkBg:"#09090b",lightBg:"#f8fafc",surfaceDark:"rgba(24,24,27,0.6)",surfaceLight:"rgba(255,255,255,0.6)"},backgroundImage:{"grid-dark":"linear-gradient(to right,#ffffff0a 1px,transparent 1px),linear-gradient(to bottom,#ffffff0a 1px,transparent 1px)","grid-light":"linear-gradient(to right,#0000000a 1px,transparent 1px),linear-gradient(to bottom,#0000000a 1px,transparent 1px)"}}}
        }
    </script>
    <style>
        body{transition:background-color .4s ease,color .4s ease}
        .glass-panel{backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);transition:all .3s ease}

        /* ══ HERO SCENE ══ */
        .hero-scene-wrap{
            position:relative;
            width:360px;
            margin:0 auto;
            display:flex;
            flex-direction:column;
            align-items:center;
        }

        /* ── CUBE ── */
        .hero-scene{width:120px;height:120px;perspective:800px;position:relative;z-index:3;margin:0 auto;}
        .hero-scene.cube-hidden{opacity:0;pointer-events:none;}
        .hero-cube{width:100%;height:100%;position:relative;transform-style:preserve-3d;cursor:grab;}
        .hero-cube.spinning{animation:spinCube 12s infinite linear;}
        .hero-cube.dragging{animation-play-state:paused;cursor:grabbing;}
        .cube-face{position:absolute;width:120px;height:120px;display:flex;align-items:center;justify-content:center;font-size:3rem;color:#8b5cf6;background:rgba(139,92,246,0.05);border:1px solid rgba(139,92,246,0.4);box-shadow:inset 0 0 20px rgba(139,92,246,0.2);backdrop-filter:blur(4px);}
        .face-front {transform:rotateY(0deg)   translateZ(60px)}
        .face-right {transform:rotateY(90deg)  translateZ(60px)}
        .face-back  {transform:rotateY(180deg) translateZ(60px)}
        .face-left  {transform:rotateY(-90deg) translateZ(60px)}
        .face-top   {transform:rotateX(90deg)  translateZ(60px)}
        .face-bottom{transform:rotateX(-90deg) translateZ(60px)}
        @keyframes spinCube{0%{transform:rotateX(0deg) rotateY(0deg) rotateZ(0deg)}100%{transform:rotateX(360deg) rotateY(360deg) rotateZ(180deg)}}

        /* ── CUBE FLOAT ── */
        @keyframes cubeFloat{
            0%,100%{transform:translateY(0px)}
            50%    {transform:translateY(-14px)}
        }
        .hero-scene.floating{animation:cubeFloat 3s ease-in-out infinite;}

        /* ── FLOATING ICON PARTICLES ── */
        .icon-particle{
            position:fixed;
            font-size:2.4rem;
            color:#8b5cf6;
            pointer-events:none;
            z-index:9999;
            filter:drop-shadow(0 0 10px #a855f7) drop-shadow(0 0 20px rgba(168,85,247,0.5));
            transform-origin:center center;
            will-change:transform,opacity;
        }

        /* ── HAND IMAGE ── */
        .hand-img-wrap{
            position:relative;
            width:360px;
            height:220px;
            margin-top:-10px;
            z-index:2;
            cursor:grab;
            user-select:none;-webkit-user-select:none;
            transform-origin:center bottom;
        }
        .hand-img-wrap:active{cursor:grabbing;}

        .hand-img{
            width:100%;height:100%;
            object-fit:contain;
            object-position:center top;
            filter:
                drop-shadow(0 0 10px #8b5cf6)
                drop-shadow(0 0 24px rgba(139,92,246,0.75))
                drop-shadow(0 0 50px rgba(139,92,246,0.4));
            transition:filter .2s;
        }
        .hand-img-wrap.grabbing .hand-img{
            filter:
                drop-shadow(0 0 16px #a855f7)
                drop-shadow(0 0 36px rgba(139,92,246,0.95))
                drop-shadow(0 0 72px rgba(168,85,247,0.7));
        }

        @keyframes neonPulse{0%,100%{opacity:1}50%{opacity:0.82}}
        .hand-img{animation:neonPulse 3s ease-in-out infinite;}
        .hand-img-wrap.grabbing .hand-img{animation:none;}

        /* drag hint */
        .drag-hint{font-size:10px;font-weight:800;letter-spacing:.18em;text-transform:uppercase;color:rgba(139,92,246,.45);text-align:center;margin-bottom:1.6rem;transition:color .2s;}
        .drag-hint.active{color:rgba(168,85,247,.95);}

        /* ═══ ZED GALAXY SLAYER HAND ANIMATION ═══ */
        @keyframes handOrb {
            0%,100% { transform: translateY(0px) rotate(0deg); }
            20%     { transform: translateY(-6px) rotate(1.5deg); }
            50%     { transform: translateY(-10px) rotate(2.5deg); }
            75%     { transform: translateY(-5px) rotate(1deg); }
        }
        @keyframes orbBeamPulse {
            0%,100% { opacity: 0.35; transform: translateX(-50%) scaleY(1); }
            50%     { opacity: 0.85; transform: translateX(-50%) scaleY(1.08); }
        }
        @keyframes orbGlowPulse {
            0%,100% { opacity: 0.5; transform: translate(-50%,-50%) scale(1); }
            50%     { opacity: 1;   transform: translate(-50%,-50%) scale(1.25); }
        }
        @keyframes orbDotPulse {
            0%,100% { transform: translateX(-30%) scale(1);   opacity:0.6; }
            50%     { transform: translateX(-30%) scale(1.6); opacity:1; }
        }
        @keyframes sparkFly0 { 0%{opacity:0;transform:translate(0,0)scale(.5)} 25%{opacity:1} 100%{opacity:0;transform:translate(-13px,-22px)scale(0)} }
        @keyframes sparkFly1 { 0%{opacity:0;transform:translate(0,0)scale(.5)} 25%{opacity:1} 100%{opacity:0;transform:translate(11px,-17px)scale(0)} }
        @keyframes sparkFly2 { 0%{opacity:0;transform:translate(0,0)scale(.5)} 25%{opacity:1} 100%{opacity:0;transform:translate(-9px,15px)scale(0)} }
        @keyframes sparkFly3 { 0%{opacity:0;transform:translate(0,0)scale(.5)} 25%{opacity:1} 100%{opacity:0;transform:translate(17px,-11px)scale(0)} }
        @keyframes sparkFly4 { 0%{opacity:0;transform:translate(0,0)scale(.5)} 25%{opacity:1} 100%{opacity:0;transform:translate(-7px,-24px)scale(0)} }

        .hand-img-wrap.zed-active { animation: handOrb 4s cubic-bezier(0.25,0.46,0.45,0.94) infinite; transform-origin: bottom center; }
        .hand-img-wrap.zed-active .hand-img { animation: neonPulse 4s ease-in-out infinite; }

        #zed-orb-glow {
            position: absolute;
            width: 140px; height: 140px;
            border-radius: 50%;
            background: radial-gradient(circle, rgba(139,92,246,0.22) 0%, rgba(139,92,246,0.06) 55%, transparent 70%);
            top: 50%; left: 50%;
            transform: translate(-50%,-50%);
            pointer-events: none;
            animation: orbGlowPulse 4s ease-in-out infinite;
            z-index: 2;
        }
        #zed-beam {
            position: absolute;
            width: 2px;
            background: linear-gradient(to bottom, rgba(139,92,246,0.6), rgba(139,92,246,0));
            left: 50%;
            border-radius: 2px;
            pointer-events: none;
            animation: orbBeamPulse 4s ease-in-out infinite;
            z-index: 1;
        }
        #zed-fingertip {
            position: absolute;
            width: 11px; height: 11px;
            border-radius: 50%;
            background: rgba(139,92,246,0.3);
            border: 1px solid rgba(139,92,246,0.7);
            pointer-events: none;
            animation: orbDotPulse 4s ease-in-out infinite;
            z-index: 5;
        }
        .zed-spark {
            position: absolute;
            width: 3px; height: 3px;
            border-radius: 50%;
            background: #a855f7;
            pointer-events: none;
            opacity: 0;
            z-index: 4;
        }

        .magnetic-card{transform-style:preserve-3d;transform:perspective(1000px)}
        .magnetic-content{transform:translateZ(30px)}
        .reveal{opacity:0;transform:translateY(30px) scale(.98);transition:all .8s cubic-bezier(.2,.8,.2,1)}
        .reveal.active{opacity:1;transform:translateY(0) scale(1)}
        .skill-bar-fill{width:0%;transition:width 1.4s cubic-bezier(.4,0,.2,1);}
        .skill-bar-wrap{position:relative;}
        .skill-pct{
            position:absolute;right:0;top:-20px;
            font-size:10px;font-weight:800;font-family:monospace;
            color:#8b5cf6;opacity:0;
            transition:opacity 0.3s ease;
        }
        .skill-pct.visible{opacity:1;}
    </style>
</head>
