<script>
document.addEventListener("DOMContentLoaded",()=>{

    /* ── THEME ── */
    const themeBtn=document.getElementById("theme-toggle"),html=document.documentElement;
    if(localStorage.theme==="dark"||(!("theme" in localStorage)&&window.matchMedia("(prefers-color-scheme:dark)").matches)){html.classList.add("dark")}else{html.classList.remove("dark")}
    themeBtn.addEventListener("click",()=>{html.classList.toggle("dark");localStorage.theme=html.classList.contains("dark")?"dark":"light"});

    /* ── MAGNETIC CARDS ── */
    document.querySelectorAll(".magnetic-card").forEach(c=>{
        c.addEventListener("mousemove",e=>{
            const r=c.getBoundingClientRect();
            const rx=((e.clientY-r.top-r.height/2)/(r.height/2))*-10;
            const ry=((e.clientX-r.left-r.width/2)/(r.width/2))*10;
            c.style.transform=`perspective(1000px) rotateX(${rx}deg) rotateY(${ry}deg) scale3d(1.02,1.02,1.02)`;
        });
        c.addEventListener("mouseleave",()=>{
            c.style.transition="transform .5s ease";
            c.style.transform="perspective(1000px) rotateX(0) rotateY(0) scale3d(1,1,1)";
            setTimeout(()=>{c.style.transition=""},500);
        });
    });

    /* ── REVEAL ON SCROLL + SKILL BARS ── */
    const obs=new IntersectionObserver(entries=>{
        entries.forEach(e=>{
            if(e.isIntersecting){
                e.target.classList.add("active");
                e.target.querySelectorAll(".skill-bar-fill").forEach(b=>{
                    setTimeout(()=>{
                        const target=parseInt(b.dataset.width);
                        b.style.width=target+"%";
                        const pct=b.closest(".skill-bar-wrap")?.querySelector(".skill-pct");
                        if(pct){
                            pct.classList.add("visible");
                            const dur=1400,start=performance.now();
                            function tick(now){
                                const p=Math.min((now-start)/dur,1);
                                const eased=1-Math.pow(1-p,3);
                                pct.textContent=Math.round(eased*target)+"%";
                                if(p<1) requestAnimationFrame(tick);
                            }
                            requestAnimationFrame(tick);
                        }
                    },250);
                });
            }
        });
    },{threshold:.1});
    document.querySelectorAll(".reveal").forEach(el=>obs.observe(el));

    /* ══════════════════════════════════════════════════════════════════
       CUBE CINEMATIC INTRO (Web Animations API)
       t=0        icons invisible, cube invisible
       t=500ms    icons burst from hand palm → orbit
       t=2600ms   cube appears, icons slam in one-by-one
       t=6500ms   cube complete → spin + float + drag + ZED animation
    ══════════════════════════════════════════════════════════════════ */
    (function(){
        const scene    = document.querySelector(".hero-scene");
        const cube     = document.getElementById("heroCube");
        const handWrap = document.getElementById("handWrap");
        const dragHint = document.getElementById("dragHint");
        const faces    = Array.from(cube.querySelectorAll(".cube-face"));

        scene.classList.add("cube-hidden");
        faces.forEach(f=>{f.style.opacity="0";});

        function rc(el){return el.getBoundingClientRect();}
        function cx(el){const r=rc(el);return r.left+r.width/2;}
        function cy(el){const r=rc(el);return r.top +r.height/2;}

        const EASE_OUT_QUART="cubic-bezier(0.25,1,0.5,1)";
        const EASE_SPRING   ="cubic-bezier(0.34,1.56,0.64,1)";

        const NUM=faces.length;
        const orbs=[];

        function orbitPos(i,handX,handY){
            const spread=260;
            const t=(i/(NUM-1))-0.5;
            const ox=handX+t*spread;
            const oy=handY-180-Math.abs(t)*80;
            return {ox,oy};
        }

        /* PHASE 1 — burst from palm */
        function phase1_burst(){
            const hx=cx(handWrap);
            const hy=cy(handWrap)+20;

            faces.forEach((face,i)=>{
                const icon=face.querySelector("i");
                const p=document.createElement("i");
                p.className=icon.className+" icon-particle";
                p.style.cssText=`position:fixed;left:${hx}px;top:${hy}px;opacity:0;z-index:9999;
                    filter:drop-shadow(0 0 10px #a855f7) drop-shadow(0 0 20px rgba(168,85,247,0.5));
                    font-size:2.4rem;color:#8b5cf6;pointer-events:none;will-change:transform,opacity;`;
                document.body.appendChild(p);
                orbs.push({el:p,face,i});

                const {ox,oy}=orbitPos(i,hx,hy);

                const appear=p.animate([
                    {opacity:0,transform:"scale(0) translate(0,0)",offset:0},
                    {opacity:1,transform:"scale(1.4) translate(0,-12px)",offset:0.2},
                    {opacity:1,transform:`scale(1) translate(${ox-hx}px,${oy-hy}px)`,offset:1}
                ],{
                    duration:900,
                    delay:i*120,
                    easing:EASE_OUT_QUART,
                    fill:"forwards"
                });

                appear.finished.then(()=>{
                    p.style.transform=`translate(${ox-hx}px,${oy-hy}px)`;
                    p.animate([
                        {transform:`translate(${ox-hx}px,${oy-hy}px)`},
                        {transform:`translate(${ox-hx}px,${oy-hy-14}px)`},
                        {transform:`translate(${ox-hx}px,${oy-hy}px)`}
                    ],{
                        duration:1800+i*200,
                        iterations:Infinity,
                        easing:"ease-in-out",
                        delay:i*80
                    });
                });
            });
        }

        /* PHASE 2 — slam icons into cube faces */
        function phase2_assemble(){
            scene.classList.remove("cube-hidden");
            scene.style.opacity="0";
            cube.style.transform="rotateX(-25deg) rotateY(35deg)";
            scene.animate([{opacity:0},{opacity:1}],{duration:600,easing:EASE_OUT_QUART,fill:"forwards"});

            const cubeX=cx(scene);
            const cubeY=cy(scene);

            orbs.forEach((orb,i)=>{
                const stagger=700*i;
                setTimeout(()=>{
                    const tr=window.getComputedStyle(orb.el).transform;
                    orb.el.style.transform=tr;
                    orb.el.getAnimations().forEach(a=>a.cancel());
                    orb.el.style.transform=tr;

                    const pr=rc(orb.el);
                    const px=pr.left+pr.width/2;
                    const py=pr.top +pr.height/2;
                    const dx=cubeX-px;
                    const dy=cubeY-py;

                    orb.el.animate([
                        {transform:`translate(0px,0px)`,opacity:1,offset:0},
                        {transform:`translate(${dx*0.1}px,-50px)`,opacity:1,offset:0.25},
                        {transform:`translate(${dx}px,${dy}px)`,opacity:1,offset:0.78},
                        {transform:`translate(${dx*1.05}px,${dy*1.05}px) scale(1.3)`,opacity:1,offset:0.83},
                        {transform:`translate(${dx}px,${dy}px) scale(0)`,opacity:0,offset:1}
                    ],{duration:800,easing:"cubic-bezier(0.22,1,0.36,1)",fill:"forwards"});

                    setTimeout(()=>{
                        scene.animate([
                            {transform:"scale(1)"},
                            {transform:"scale(1.08)"},
                            {transform:"scale(0.95)"},
                            {transform:"scale(1)"}
                        ],{duration:280,easing:"ease-in-out"});

                        orb.face.style.opacity="0";
                        orb.face.animate([
                            {opacity:0,filter:"brightness(4)"},
                            {opacity:1,filter:"brightness(1.8)"},
                            {opacity:1,filter:"brightness(1)"}
                        ],{duration:350,easing:EASE_SPRING,fill:"forwards"});
                        orb.face.style.opacity="1";

                        if(orb.el.parentNode) orb.el.parentNode.removeChild(orb.el);
                    },620);
                },stagger);
            });

            /* After all slams → spin, float, drag, ZED */
            const done=700*(NUM-1)+1200;
            setTimeout(()=>{
                killAllParticles();
                cube.style.transition="transform 0.8s "+EASE_OUT_QUART;
                cube.style.transform="rotateX(0deg) rotateY(0deg)";
                setTimeout(()=>{
                    cube.style.transition="";
                    cube.classList.add("spinning");
                    scene.classList.add("floating");
                    enableDrag(); /* this also activates Zed */
                },850);
            },done);

            setTimeout(killAllParticles,8000);
        }

        function killAllParticles(){
            orbs.forEach(o=>{
                o.el.getAnimations().forEach(a=>a.cancel());
                if(o.el.parentNode) o.el.parentNode.removeChild(o.el);
            });
            orbs.length=0;
            document.querySelectorAll(".icon-particle").forEach(el=>el.remove());
        }

        window.addEventListener("scroll",killAllParticles,{once:true,passive:true});
        document.addEventListener("visibilitychange",()=>{if(document.hidden) killAllParticles();},{once:true});

        setTimeout(phase1_burst,500);
        setTimeout(phase2_assemble,2600);

        /* ══════════════════════════════════════════════════
           DRAG / INERTIA
        ══════════════════════════════════════════════════ */
        let isDragging=false,lastX=0,lastY=0,rotX=0,rotY=0,velX=0,velY=0;
        const SPIN_MS=12000;
        let spinStart=performance.now(),resumeTimer=null,dragEnabled=false;

        function getAutoRot(){
            const p=((performance.now()-spinStart)%SPIN_MS)/SPIN_MS;
            return{x:p*360,y:p*360};
        }
        function applyRot(){cube.style.transform=`rotateX(${rotX}deg) rotateY(${rotY}deg)`;}

        function startDrag(e){
            if(!dragEnabled) return;
            e.preventDefault();
            isDragging=true;
            const a=getAutoRot();rotX=a.x;rotY=a.y;
            cube.classList.remove("spinning");
            cube.style.transition="none";
            applyRot();
            cube.classList.add("dragging");
            handWrap.classList.add("grabbing");
            dragHint.classList.add("active");
            dragHint.textContent="\u2726 spinning";
            const pt=e.touches?e.touches[0]:e;
            lastX=pt.clientX;lastY=pt.clientY;
            velX=0;velY=0;
            if(resumeTimer) clearTimeout(resumeTimer);
        }
        function onMove(e){
            if(!isDragging) return;
            const pt=e.touches?e.touches[0]:e;
            velX=pt.clientX-lastX;velY=pt.clientY-lastY;
            rotY+=velX*0.5;rotX-=velY*0.5;
            lastX=pt.clientX;lastY=pt.clientY;
            applyRot();
        }
        function endDrag(){
            if(!isDragging) return;
            isDragging=false;
            cube.classList.remove("dragging");
            handWrap.classList.remove("grabbing");
            dragHint.classList.remove("active");
            dragHint.textContent="\u2194 drag to spin the cube";
            let vx=velX*0.5,vy=velY*0.5;
            function coast(){
                if(Math.abs(vx)<0.3&&Math.abs(vy)<0.3){
                    if(!isDragging){cube.classList.add("spinning");spinStart=performance.now();}
                    return;
                }
                rotY+=vx;rotX-=vy;vx*=0.88;vy*=0.88;
                applyRot();
                requestAnimationFrame(coast);
            }
            resumeTimer=setTimeout(coast,2500);
        }

        /* ══════════════════════════════════════════════════
           ZED GALAXY SLAYER — activates after assembly done
        ══════════════════════════════════════════════════ */
        function activateZed(){
            const wrap      = document.getElementById("handWrap");
            const sceneEl   = document.getElementById("heroScene");
            const beam      = document.getElementById("zed-beam");
            const glow      = document.getElementById("zed-orb-glow");
            const dot       = document.getElementById("zed-fingertip");
            const sparks    = document.querySelectorAll(".zed-spark");
            if(!wrap||!sceneEl||!beam) return;

            const wrapR      = wrap.getBoundingClientRect();
            const sceneR     = sceneEl.getBoundingClientRect();
            const parentR    = wrap.parentElement.getBoundingClientRect();

            /* fingertip = ~18% from top of hand image (index finger tip) */
            const fingertipAbsY  = wrapR.top  + wrapR.height  * 0.18;
            const cubeBottomAbsY = sceneR.bottom;
            const beamHeight     = Math.max(0, fingertipAbsY - cubeBottomAbsY);

            /* positions relative to .hero-scene-wrap */
            const parentTop  = parentR.top;
            const parentLeft = parentR.left;

            /* beam: centred on cube, spans cube-bottom → fingertip */
            const cubeCentreX = sceneR.left + sceneR.width / 2 - parentLeft;
            beam.style.left   = cubeCentreX + "px";
            beam.style.top    = (cubeBottomAbsY - parentTop) + "px";
            beam.style.height = beamHeight + "px";

            /* fingertip dot */
            const fingertipX = wrapR.left + wrapR.width * 0.33 - parentLeft;
            const fingertipY = fingertipAbsY - parentTop;
            dot.style.left   = (fingertipX - 5.5) + "px";
            dot.style.top    = (fingertipY - 5.5) + "px";

            /* sparks cluster at cube centre */
            const sparkX = cubeCentreX;
            const sparkY = sceneR.top + sceneR.height * 0.5 - parentTop;
            sparks.forEach(s=>{
                s.style.left = sparkX + "px";
                s.style.top  = sparkY + "px";
            });

            /* fade everything in */
            requestAnimationFrame(()=>{
                beam.style.opacity    = "1";
                glow.style.opacity    = "1";
                dot.style.opacity     = "1";
                sparks.forEach(s=>{ s.style.opacity = ""; });
                wrap.classList.add("zed-active");
            });
        }

        function enableDrag(){
            activateZed(); /* ← Zed fires here, after cinematic */

            dragEnabled=true;
            [cube,handWrap].forEach(el=>{
                el.addEventListener("mousedown",startDrag);
                el.addEventListener("touchstart",startDrag,{passive:false});
            });
            document.addEventListener("mousemove",onMove);
            document.addEventListener("touchmove",onMove,{passive:false});
            document.addEventListener("mouseup",endDrag);
            document.addEventListener("touchend",endDrag);
        }

    })(); /* end hero IIFE */

}); /* end DOMContentLoaded */
</script>
